import { once } from 'node:events';
import dgram, { type RemoteInfo } from 'node:dgram';
import { createServer, type IncomingMessage, type ServerResponse } from 'node:http';
import {
  PROTOCOL69_EXPECTED_PROJECTION,
  PROTOCOL69_NAME,
  PROTOCOL69_SCHEMA_VERSION,
  PROTOCOL69_WORD_NAME,
  buildProtocol69ProjectionEnvelope,
  protocol69Projection,
  type Protocol69ProjectionEnvelope,
} from '../src/protocol69.js';

const FLOW_HEADER_SIZE = 10;
const FLOW_FLAGS_FORK_RACE_FOLD_VENT = 0b0000_1111;

type ProbeTransport = 'http' | 'flow-udp' | 'both';

interface ProbeCli {
  readonly url: string;
  readonly flowHost: string;
  readonly flowPort: number;
  readonly flowPath: string;
  readonly transport: ProbeTransport;
  readonly timeoutMs: number;
  readonly selfTest: boolean;
  readonly printEnvelope: boolean;
}

interface ProbeResult {
  readonly ok: boolean;
  readonly status: number;
  readonly body: unknown;
}

function usage(): string {
  return [
    'Usage: pnpm run protocol69:foil-probe -- [--url <http://host:port/.aeon/protocol69>] [--timeout-ms <ms>] [--print-envelope] [--self-test]',
    '       pnpm run protocol69:foil-probe -- --transport flow-udp [--flow-host 127.0.0.1] [--flow-port 9082] [--flow-path /.aeon/protocol69]',
    '',
    'Posts the TypeScript @a0n/gnosis/protocol69 envelope to a gnosis-foil-control protocol69 validation endpoint.',
  ].join('\n');
}

function parseCli(argv: readonly string[]): ProbeCli {
  let url = process.env.GNOSIS_PROTOCOL69_FOIL_URL ?? 'http://127.0.0.1:8787/.aeon/protocol69';
  let flowHost = process.env.GNOSIS_PROTOCOL69_FLOW_HOST ?? '127.0.0.1';
  let flowPort = Number.parseInt(process.env.GNOSIS_PROTOCOL69_FLOW_PORT ?? '9082', 10);
  let flowPath = process.env.GNOSIS_PROTOCOL69_FLOW_PATH ?? '/.aeon/protocol69';
  let transport: ProbeTransport = 'http';
  let timeoutMs = Number.parseInt(process.env.GNOSIS_PROTOCOL69_TIMEOUT_MS ?? '5000', 10);
  let selfTest = false;
  let printEnvelope = false;

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i];
    if (arg === '--') {
      continue;
    }
    if (arg === '--help' || arg === '-h') {
      console.log(usage());
      process.exit(0);
    }
    if (arg === '--self-test') {
      selfTest = true;
      continue;
    }
    if (arg === '--print-envelope') {
      printEnvelope = true;
      continue;
    }
    if (arg === '--url') {
      const value = argv[++i];
      if (!value) throw new Error('--url requires a value');
      url = value;
      continue;
    }
    if (arg === '--flow-host') {
      const value = argv[++i];
      if (!value) throw new Error('--flow-host requires a value');
      flowHost = value;
      continue;
    }
    if (arg === '--flow-port') {
      const value = argv[++i];
      if (!value) throw new Error('--flow-port requires a value');
      flowPort = Number.parseInt(value, 10);
      continue;
    }
    if (arg === '--flow-path') {
      const value = argv[++i];
      if (!value) throw new Error('--flow-path requires a value');
      flowPath = value;
      continue;
    }
    if (arg === '--transport') {
      const value = argv[++i];
      if (value !== 'http' && value !== 'flow-udp' && value !== 'both') {
        throw new Error('--transport must be http, flow-udp, or both');
      }
      transport = value;
      continue;
    }
    if (arg === '--timeout-ms') {
      const value = argv[++i];
      if (!value) throw new Error('--timeout-ms requires a value');
      timeoutMs = Number.parseInt(value, 10);
      continue;
    }
    throw new Error(`unknown argument: ${arg}\n${usage()}`);
  }

  if (!Number.isFinite(timeoutMs) || timeoutMs <= 0) {
    throw new Error('--timeout-ms must be a positive integer');
  }
  if (!Number.isInteger(flowPort) || flowPort <= 0 || flowPort > 65535) {
    throw new Error('--flow-port must be a valid UDP port');
  }
  return { url, flowHost, flowPort, flowPath, transport, timeoutMs, selfTest, printEnvelope };
}

function validateCanonicalEnvelope(envelope: Protocol69ProjectionEnvelope): string | null {
  if (envelope.schemaVersion !== PROTOCOL69_SCHEMA_VERSION) return 'schemaVersion mismatch';
  if (envelope.protocol !== PROTOCOL69_NAME) return 'protocol mismatch';
  if (envelope.wordName !== PROTOCOL69_WORD_NAME) return 'wordName mismatch';
  if (envelope.expectedProjection !== PROTOCOL69_EXPECTED_PROJECTION) {
    return 'expectedProjection mismatch';
  }
  const projection = protocol69Projection(envelope.broadcastSymbol, envelope.localFoilOperand);
  if (projection !== envelope.expectedProjection) {
    return `projection mismatch: got ${projection}`;
  }
  return null;
}

function readBody(request: IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    let body = '';
    request.setEncoding('utf8');
    request.on('data', (chunk: string) => {
      body += chunk;
    });
    request.on('end', () => resolve(body));
    request.on('error', reject);
  });
}

async function startSelfTestServer(): Promise<{
  readonly url: string;
  readonly flowHost: string;
  readonly flowPort: number;
  readonly close: () => Promise<void>;
}> {
  const server = createServer(async (request: IncomingMessage, response: ServerResponse) => {
    if (request.method !== 'POST' || request.url?.split('?')[0] !== '/.aeon/protocol69') {
      response.writeHead(404, { 'Content-Type': 'application/json' });
      response.end(JSON.stringify({ status: 'not_found' }));
      return;
    }

    try {
      const raw = await readBody(request);
      const envelope = JSON.parse(raw) as Protocol69ProjectionEnvelope;
      const error = validateCanonicalEnvelope(envelope);
      if (error) {
        response.writeHead(400, { 'Content-Type': 'application/json' });
        response.end(JSON.stringify({ status: 'rejected', reason: error }));
        return;
      }
      response.writeHead(200, { 'Content-Type': 'application/json' });
      response.end(JSON.stringify({ status: 'validated', projection: envelope }));
    } catch (error) {
      response.writeHead(400, { 'Content-Type': 'application/json' });
      response.end(JSON.stringify({ status: 'rejected', reason: String(error) }));
    }
  });
  const udp = dgram.createSocket('udp4');
  const httpListening = once(server, 'listening');
  const udpListening = once(udp, 'listening');
  server.listen(0, '127.0.0.1');
  udp.on('message', (message: Buffer, remote: RemoteInfo) => {
    try {
      const frame = decodeFlowFrame(message);
      const path = frame.payload.toString('utf8').split(/\s/u)[0];
      const body =
        path === '/.aeon/protocol69'
          ? JSON.stringify({
              status: 'ok',
              service: 'gnosis-foil',
              transport: 'flow-udp',
              projection: buildProtocol69ProjectionEnvelope(),
            })
          : JSON.stringify({ status: 'not_found', path });
      udp.send(
        encodeFlowFrame({ streamId: frame.streamId, sequence: frame.sequence, payload: body }),
        remote.port,
        remote.address,
      );
    } catch (error) {
      const body = JSON.stringify({ status: 'rejected', reason: String(error) });
      udp.send(encodeFlowFrame({ streamId: 1, sequence: 0, payload: body }), remote.port, remote.address);
    }
  });
  udp.bind(0, '127.0.0.1');
  await httpListening;
  await udpListening;
  const address = server.address();
  const udpAddress = udp.address();
  if (
    address === null ||
    typeof address === 'string' ||
    udpAddress === null ||
    typeof udpAddress === 'string'
  ) {
    throw new Error('self-test server did not bind to a TCP port');
  }
  return {
    url: `http://127.0.0.1:${address.port}/.aeon/protocol69`,
    flowHost: '127.0.0.1',
    flowPort: udpAddress.port,
    close: async () => {
      const httpClosed = once(server, 'close');
      const udpClosed = once(udp, 'close');
      server.close();
      udp.close();
      await httpClosed;
      await udpClosed;
    },
  };
}

function encodeFlowFrame(opts: {
  readonly streamId: number;
  readonly sequence: number;
  readonly payload: string | Buffer;
}): Buffer {
  const payload = Buffer.isBuffer(opts.payload) ? opts.payload : Buffer.from(opts.payload);
  if (payload.length > 0x00ff_ffff) {
    throw new Error('payload exceeds 24-bit Aeon Flow frame length');
  }
  const frame = Buffer.alloc(FLOW_HEADER_SIZE + payload.length);
  frame.writeUInt16BE(opts.streamId, 0);
  frame.writeUInt32BE(opts.sequence, 2);
  frame[6] = FLOW_FLAGS_FORK_RACE_FOLD_VENT;
  frame[7] = (payload.length >> 16) & 0xff;
  frame[8] = (payload.length >> 8) & 0xff;
  frame[9] = payload.length & 0xff;
  payload.copy(frame, FLOW_HEADER_SIZE);
  return frame;
}

function decodeFlowFrame(bytes: Buffer): {
  readonly streamId: number;
  readonly sequence: number;
  readonly flags: number;
  readonly payload: Buffer;
} {
  if (bytes.length < FLOW_HEADER_SIZE) {
    throw new Error('buffer smaller than Aeon Flow header');
  }
  const payloadLength = (bytes[7]! << 16) | (bytes[8]! << 8) | bytes[9]!;
  if (bytes.length < FLOW_HEADER_SIZE + payloadLength) {
    throw new Error('incomplete Aeon Flow payload');
  }
  return {
    streamId: bytes.readUInt16BE(0),
    sequence: bytes.readUInt32BE(2),
    flags: bytes[6]!,
    payload: bytes.subarray(FLOW_HEADER_SIZE, FLOW_HEADER_SIZE + payloadLength),
  };
}

async function postEnvelope(url: string, timeoutMs: number): Promise<ProbeResult> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(buildProtocol69ProjectionEnvelope()),
      signal: controller.signal,
    });
    const text = await response.text();
    let body: unknown = text;
    if (text.trim() !== '') {
      try {
        body = JSON.parse(text) as unknown;
      } catch {
        body = text;
      }
    }
    return { ok: response.ok, status: response.status, body };
  } finally {
    clearTimeout(timeout);
  }
}

async function requestFlowEnvelope(
  host: string,
  port: number,
  path: string,
  timeoutMs: number,
): Promise<ProbeResult> {
  const socket = dgram.createSocket('udp4');
  try {
    const frame = encodeFlowFrame({ streamId: 1, sequence: 0, payload: path });
    const response = await new Promise<Buffer>((resolve, reject) => {
      const timeout = setTimeout(() => {
        reject(new Error(`Flow/UDP timeout after ${timeoutMs}ms`));
      }, timeoutMs);
      socket.once('message', (message: Buffer) => {
        clearTimeout(timeout);
        resolve(message);
      });
      socket.once('error', (error: Error) => {
        clearTimeout(timeout);
        reject(error);
      });
      socket.send(frame, port, host);
    });
    const payload = decodeFlowFrame(response).payload.toString('utf8');
    let body: unknown = payload;
    if (payload.trim() !== '') {
      try {
        body = JSON.parse(payload) as unknown;
      } catch {
        body = payload;
      }
    }
    const ok = validateProbeResponse(body) === null;
    return { ok, status: ok ? 200 : 502, body };
  } finally {
    socket.close();
  }
}

function validateProbeResponse(body: unknown): string | null {
  if (typeof body !== 'object' || body === null || !('projection' in body)) {
    return 'response missing projection';
  }
  const projection = (body as { readonly projection?: unknown }).projection;
  if (typeof projection !== 'object' || projection === null) {
    return 'response projection is not an object';
  }
  return validateCanonicalEnvelope(projection as Protocol69ProjectionEnvelope);
}

async function main(): Promise<void> {
  const cli = parseCli(process.argv.slice(2));
  if (cli.printEnvelope) {
    console.log(JSON.stringify(buildProtocol69ProjectionEnvelope(), null, 2));
  }

  let selfTestServer: Awaited<ReturnType<typeof startSelfTestServer>> | null = null;
  if (cli.selfTest) {
    selfTestServer = await startSelfTestServer();
  }
  const url = selfTestServer?.url ?? cli.url;
  const flowHost = selfTestServer?.flowHost ?? cli.flowHost;
  const flowPort = selfTestServer?.flowPort ?? cli.flowPort;

  try {
    const httpResult =
      cli.transport === 'http' || cli.transport === 'both'
        ? await postEnvelope(url, cli.timeoutMs)
        : null;
    const flowResult =
      cli.transport === 'flow-udp' || cli.transport === 'both'
        ? await requestFlowEnvelope(flowHost, flowPort, cli.flowPath, cli.timeoutMs)
        : null;
    const ok = (httpResult?.ok ?? true) && (flowResult?.ok ?? true);
    console.log(
      JSON.stringify(
        {
          protocol69FoilProbe: {
            transport: cli.transport,
            ok,
            http: httpResult
              ? { url, ok: httpResult.ok, status: httpResult.status, response: httpResult.body }
              : null,
            flowUdp: flowResult
              ? {
                  host: flowHost,
                  port: flowPort,
                  path: cli.flowPath,
                  ok: flowResult.ok,
                  status: flowResult.status,
                  response: flowResult.body,
                }
              : null,
          },
        },
        null,
        2,
      ),
    );
    if (!ok) process.exitCode = 2;
  } finally {
    await selfTestServer?.close();
  }
}

main().catch((error: unknown) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exitCode = 1;
});
